  ('dietitian-moex-01303', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '健康人飢餓狀態持續一週，其體內能量的利用與適應期內的相關機制之敘述，下列何者錯誤？', '["支鏈胺基酸首先被分解，作為主要能量來源", "血糖降低後使得胰島素分泌減少", "體內儲存的肝醣約在24小時之後幾乎被耗盡", "肝醣耗盡後肝臟的醣質新生作用亦降低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01304', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '重症病人常發生腸阻塞（ileus）而延緩腸道營養支持的進展，有關此狀況的敘述下列何者錯誤？', '["可能因休克時腸道血流灌流不足而致", "腸道的絨毛萎縮，影響腸相關淋巴組織的「分泌性免疫細胞」", "給予靜脈營養可維持腸道功能和上皮細胞的tightjunctions", "缺乏灌流的腸道會導致促發炎物質的產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01305', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '針對手術前後的營養支持與介入注意事項，下列何者錯誤？', '["麻醉前六小時應禁止進食固體食物、兩小時前禁止進食清流質食物，以避免吸入性肺炎", "若病人營養不良且預期腸道營養於術後5-7天無法順利進展，則手術前、後應給予靜脈營養， 直到腸道營養達到目標", "若病人在術後需延長禁食的時間，應該在手術時合併施放胃造口和空腸造口，並使用胃造口灌 食、空腸造口引流", "術後經評估，若病人可開始經口進食，也可優先吃固體食物，不一定只能從清流質開始"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01306', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '消化性潰瘍常見於那一種細菌的感染？', '["李氏特菌", "肉毒桿菌", "幽門螺旋桿菌", "沙門氏菌"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
